import React, { useState, useEffect } from 'react';
import axios from 'axios';
import '../assets/styles/MicrosoftTeams.css';

const MicrosoftTeams = () => {
  const [contacts, setContacts] = useState([]);
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Verifică autentificarea
  const [loadingContacts, setLoadingContacts] = useState(false);

  // Verifică starea autentificării când componenta este montată
  useEffect(() => {
    checkAuthentication();
  }, []);

  // Funcție pentru verificarea stării autentificării
  const checkAuthentication = async () => {
    try {
      const response = await axios.get('/teams/auth/status'); // Endpoint pentru verificarea autentificării
      setIsAuthenticated(response.data.isAuthenticated);
    } catch (error) {
      console.error('Error checking authentication:', error);
    }
  };

  // Funcție care redirecționează utilizatorul către Microsoft Teams pentru autentificare
  const handleLogin = () => {
    window.location.href = '/teams/login'; // Redirecționează utilizatorul la pagina de login
  };

  // Funcție pentru preluarea contactelor din Microsoft Teams după autentificare
  const fetchContacts = async () => {
    if (!isAuthenticated) {
      console.log("Utilizatorul nu este autentificat.");
      return;
    }

    setLoadingContacts(true); // Afișează mesajul de încărcare
    try {
      const response = await axios.get('/teams/contacts'); // Endpoint pentru a obține contactele
      setContacts(response.data); // Salvează contactele în state
    } catch (error) {
      console.error('There was an error fetching the contacts!', error);
    } finally {
      setLoadingContacts(false); // Ascunde mesajul de încărcare
    }
  };

  return (
    <div className="teams-container">
      <h1 className="title">Microsoft Teams</h1>

      {/* Dacă utilizatorul nu este autentificat, afișează butonul de conectare */}
      {!isAuthenticated ? (
        <button onClick={handleLogin} className="button">
          Conectare la Microsoft Teams
        </button>
      ) : (
        // Dacă utilizatorul este autentificat, afișează butonul pentru preluarea contactelor
        <div>
          <button onClick={fetchContacts} className="button">
            Preia Contactele din Microsoft Teams
          </button>
        </div>
      )}

      {/* Afișează mesajul de încărcare dacă datele se preiau */}
      {loadingContacts && <p>Se încarcă contactele...</p>}

      {/* Afișează lista contactelor dacă acestea sunt disponibile */}
      {contacts.length > 0 && (
        <div className="contacts-list">
          <h2>Contacts</h2>
          <ul>
            {contacts.map(contact => (
              <li key={contact.id}>
                <span>{contact.displayName}</span>
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

export default MicrosoftTeams;





